DROP TABLE IF EXISTS Sondage_Poudlard;
CREATE TABLE Sondage_Poudlard (
    id INT PRIMARY KEY,
    nom_complet VARCHAR(100),
    sexe VARCHAR(20),
    date_naissance DATE,
    continent VARCHAR(50),
    pays VARCHAR(50),
    niveau_etude INT,
    secteur_activite VARCHAR(100),
    sport_prefere VARCHAR(100),
    film_prefere VARCHAR(100),
    chanson_preferee VARCHAR(100),
    couleur_preferee VARCHAR(50),
    situation_familiale VARCHAR(50),
    richesse VARCHAR(50),
    maison VARCHAR(50),
    statut_sang VARCHAR(50),
    animal_compagnon VARCHAR(50)
);

